const data = ($input.first().json?.data || $input.first().json) || {};
const fileName = $('Google Drive Trigger')?.item?.json?.name || 'Unknown';
const fileId   = $('Google Drive Trigger')?.item?.json?.id   || '';

const attendeeList  = data.attendeesList || 'Not specified';
const attendeeCount = attendeeList !== 'Not specified'
  ? attendeeList.split(',').filter(a => a.trim()).length : 0;

const decisions = (data.decisionsList || '').split(';').map(d => d.trim()).filter(Boolean);
const decisionList  = decisions.map(d => `✓ ${d}`).join('\n') || 'None recorded';
const decisionCount = decisions.length;

const actions = (data.actionItemsList || '').split(';').map(a => a.trim()).filter(Boolean);
const actionList = actions.map(a => {
  const parts = a.split('|').map(p => p.trim());
  return `▫ ${parts[0] || a} → ${parts[1] || 'TBD'} (Due: ${parts[2] || 'TBD'}) [${parts[3] || 'Medium'}]`;
}).join('\n') || 'None assigned';
const actionCount = actions.length;
const highPriorityCount = actions.filter(a => a.toLowerCase().includes('high')).length;

return [{ json: {
  meetingTitle:      data.meetingTitle      || 'Unknown Meeting',
  meetingDate:       data.meetingDate       || 'N/A',
  meetingDuration:   data.meetingDuration   || 'N/A',
  attendeeList,
  attendeeCount,
  discussionSummary: data.discussionSummary || 'N/A',
  decisionList,
  decisionCount,
  actionList,
  actionCount,
  highPriorityCount,
  followUpDate:    data.followUpDate    || 'N/A',
  followUpPurpose: data.followUpPurpose || 'N/A',
  parkingLotList:  data.parkingLotList  || 'None',
  fileName,
  fileId,
  processedAt: new Date().toISOString()
}}];

